hibernate-mapping.sql-query:
        
           declare @modifiedBySeq int;
		   set @modifiedBySeq = (select Modified_By_Seq from cabinet..ROI_RequestCoreCharges 
		   where ROI_RequestCore_Seq = :requestCoreId)
           INSERT INTO  cabinet..ROI_RequestCoreDelivery (ROI_RequestCore_Seq, Created_By_Seq, 
           Modified_By_Seq) VALUES (:requestCoreId, @modifiedBySeq, @modifiedBySeq);
           SELECT SCOPE_IDENTITY() as requestCoreDeliveryId;

INSERT INTO cabinet..ROI_RequestCoreDeliverytoROI_Pages( ROI_RequestCoreDelivery_Seq, ROI_Pages_Seq, PAYOR_SELF_PAY)
VALUES (
:requestCoreDeliveryId, :roiPagesId, :selfPayEncounter);
UPDATE cabinet..ROI_Pages set IsReleased = 1, SelectedForRelease = 0 where ROI_Pages_Seq = :roiPagesId ;

        
			INSERT INTO cabinet..ROI_RequestCoreDeliverytoROI_SupplementalAttachmentsCore(ROI_RequestCoreDelivery_Seq,ROI_SupplementalAttachmentsCore_Seq)
			VALUES ( :requestCoreDeliveryId, :roiSupplementalAttachmentId);
			UPDATE cabinet..ROI_SupplementalAttachmentsCore set isreleased = 1, SelectedForRelease = 0 where ROI_SupplementalAttachmentsCore_Seq=:roiSupplementalAttachmentId ;

        
			INSERT INTO cabinet..ROI_RequestCoreDeliverytoROI_SupplementalDocumentsCore(ROI_RequestCoreDelivery_Seq,ROI_SupplementalDocumentsCore_Seq)
			VALUES ( :requestCoreDeliveryId, :roiSupplementalDocumentId);
			UPDATE cabinet..ROI_SupplementalDocumentsCore set isreleased = 1, SelectedForRelease = 0 where ROI_SupplementalDocumentsCore_Seq=:roiSupplementalDocumentId ;

        
			INSERT INTO cabinet..ROI_RequestCoreDeliverytoROI_SupplementarityAttachmentsCore(ROI_RequestCoreDelivery_Seq,ROI_SupplementarityAttachmentsCore_Seq)
			VALUES ( :requestCoreDeliveryId, :roiSupplementarityAttachmentId);
			UPDATE cabinet..ROI_SupplementarityAttachmentsCore set isreleased = 1, SelectedForRelease = 0 where ROI_SupplementarityAttachmentsCore_Seq=:roiSupplementarityAttachmentId ;

        
			INSERT INTO cabinet..ROI_RequestCoreDeliverytoROI_SupplementarityDocumentsCore(ROI_RequestCoreDelivery_Seq,ROI_SupplementarityDocumentsCore_Seq)
			VALUES ( :requestCoreDeliveryId, :roiSupplementarityDocumentId);
			UPDATE cabinet..ROI_SupplementarityDocumentsCore set isreleased = 1, SelectedForRelease = 0 where ROI_SupplementarityDocumentsCore_Seq = :roiSupplementarityDocumentId ;
